// Parse incoming Telegram command
const message = $input.item.json.message || $input.item.json.edited_message;
const text = message?.text || '';
const chatId = message?.chat?.id;
const userId = message?.from?.id;
const username = message?.from?.username || 'unknown';

const command = text.split(' ')[0].toLowerCase();
const args = text.substring(command.length).trim();

// Return as array (CRITICAL FIX)
return [{
  command,
  args,
  chatId,
  userId,
  username,
  fullText: text,
  timestamp: new Date().toISOString(),
  messageId: message?.message_id
}];

// Parse portfolio input with error handling
try {
  const args = $input.item.json.args;
  const chatId = $input.item.json.chatId;
  const userId = $input.item.json.userId;
  const username = $input.item.json.username;

  // If no args, user wants to view portfolio
  if (!args || args.trim() === '') {
    return [{
      action: 'view',
      chatId,
      userId
    }];
  }

  const holdings = [];
  const errors = [];
  const pairs = args.split(',');

  for (const pair of pairs) {
    const [symbol, qty] = pair.trim().split(':');

    if (symbol && qty) {
      const quantity = parseFloat(qty);
      if (isNaN(quantity) || quantity <= 0) {
        errors.push(`Invalid quantity for ${symbol}: ${qty}`);
      } else {
        holdings.push({
          symbol: symbol.trim().toUpperCase(),
          quantity: quantity,
          userId: userId,
          username: username
        });
      }
    } else {
      errors.push(`Invalid format: ${pair}`);
    }
  }

  if (errors.length > 0 && holdings.length === 0) {
    return [{
      error: true,
      chatId,
      message: `❌ Errors found:\n${errors.join('\n')}\n\nFormat: /portfolio SYMBOL:QUANTITY,SYMBOL:QUANTITY\nExample: /portfolio AAPL:100,BTC:0.5`
    }];
  }

  return [{
    action: 'set',
    holdings,
    chatId,
    userId,
    username,
    errors: errors.length > 0 ? errors : null
  }];

} catch (error) {
  return [{
    error: true,
    chatId: $input.item.json.chatId,
    message: `❌ Error parsing portfolio: ${error.message}`
  }];
}

// Classify assets and enrich with metadata
try {
  const holdings = $input.item.json.holdings;

  const cryptoSymbols = ['BTC', 'ETH', 'SOL', 'ADA', 'XRP', 'DOGE', 'MATIC', 'DOT', 'AVAX', 'LINK', 'UNI', 'ATOM', 'NEAR', 'APT', 'ARB'];
  const commoditySymbols = ['GOLD', 'SILVER', 'OIL', 'GAS', 'COPPER', 'PLATINUM', 'PALLADIUM'];
  const bondSymbols = ['TLT', 'AGG', 'BND', 'IEF', 'SHY', 'LQD', 'HYG', 'MUB'];

  const enriched = holdings.map(holding => {
    const symbol = holding.symbol;
    let assetType = 'Stock';
    let apiSource = 'polygon';
    let coinId = null;

    if (cryptoSymbols.includes(symbol)) {
      assetType = 'Crypto';
      apiSource = 'coingecko';
      // Map to CoinGecko IDs
      const coinMap = {
        'BTC': 'bitcoin', 'ETH': 'ethereum', 'SOL': 'solana',
        'ADA': 'cardano', 'XRP': 'ripple', 'DOGE': 'dogecoin',
        'MATIC': 'matic-network', 'DOT': 'polkadot', 'AVAX': 'avalanche-2',
        'LINK': 'chainlink', 'UNI': 'uniswap', 'ATOM': 'cosmos',
        'NEAR': 'near', 'APT': 'aptos', 'ARB': 'arbitrum'
      };
      coinId = coinMap[symbol] || symbol.toLowerCase();
    } else if (commoditySymbols.includes(symbol)) {
      assetType = 'Commodity';
      apiSource = 'twelvedata';
    } else if (bondSymbols.includes(symbol)) {
      assetType = 'Bond';
      apiSource = 'polygon';
    }

    return {
      ...holding,
      assetType,
      apiSource,
      coinId
    };
  });

  return [{
    holdings: enriched,
    chatId: $input.item.json.chatId,
    userId: $input.item.json.userId,
    username: $input.item.json.username
  }];

} catch (error) {
  return [{
    error: true,
    message: `Error classifying assets: ${error.message}`,
    chatId: $input.item.json.chatId
  }];
}

