// ✅ Aggregate Portfolio Data (Full Fixed Version)
// Handles Polygon + TwelveData + base holding
// Adds volatility, Sharpe Ratio & PnL % even without cost basis

// ---------- helpers ----------
const safeItems = (nodeName) => {
  try { return $items(nodeName, 0, 0)?.json || null; }
  catch { return null; } // node didn't execute; avoid n8n "unexecuted" error
};

const isPlainObject = (o) =>
  o && typeof o === 'object' && !Array.isArray(o) && Object.keys(o).length > 0;

// Extract most recent bar from Polygon /v2/aggs/ticker/*/prev
const fromPolygon = (o) => {
  if (!o || !o.ticker || !Array.isArray(o.results) || !o.results.length) return null;
  const r = o.results[0];
  return {
    source: 'polygon:prev',
    price:  Number(r.c ?? 0),
    open:   r.o ?? null,
    high:   r.h ?? null,
    low:    r.l ?? null,
    vwap:   r.vw ?? null,
    volume: r.v ?? null,
    barTime: (r.t != null) ? new Date(Number(r.t)).toISOString() : null,
    symbolHint: o.ticker
  };
};

// Extract most recent bar from TwelveData time series
const fromTwelve = (o) => {
  if (!o || !o.meta || !Array.isArray(o.values) || !o.values.length) return null;
  const v = o.values[0];
  const num = (x) => (x == null ? null : Number(x));
  return {
    source: 'twelvedata:timeseries',
    price:  num(v.close) ?? 0,
    open:   num(v.open),
    high:   num(v.high),
    low:    num(v.low),
    vwap:   null,                     // TwelveData 1h series doesn't include VWAP
    volume: num(v.volume),
    barTime: v.datetime ? new Date(v.datetime.replace(' ', 'T') + 'Z').toISOString() : null,
    symbolHint: o.meta.symbol
  };
};

// Pick the first object that looks like your base holding (symbol/quantity etc.)
const findBaseInInputs = (arr) =>
  arr.find(o => (o.symbol || o.assetType || o.apiSource || o.chatId)) || null;

// ---------- ingest inputs ----------
const allItems = $input.all().map(x => x.json).filter(isPlainObject);

// also try to read base holding from the classify-node (if it ran)
const baseFromNode =
  safeItems('classify asset types') ||
  safeItems('Classify Asset Types') ||
  null;

// merge precedence: explicit base from inputs > node > {}
const base = findBaseInInputs(allItems) || baseFromNode || {};

// pull market data objects from the Merge inputs
const polyObj   = allItems.find(o => o.ticker && o.results);
const twelveObj = allItems.find(o => o.meta && o.values);

// normalize price snapshots
const poly    = fromPolygon(polyObj);
const twelve  = fromTwelve(twelveObj);

// ---------- build normalized holding ----------
const symbol = String(
  base.symbol ??
  poly?.symbolHint ??
  twelve?.symbolHint ??
  'UNKNOWN'
);

const qty = Number(base.quantity ?? 0);

// price precedence: Polygon → TwelveData → base.currentPrice/price → 0
const price =
  (poly?.price ?? null) ??
  (twelve?.price ?? null) ??
  Number(base.currentPrice ?? base.price ?? 0);

const open   = (poly?.open   ?? twelve?.open   ?? base.open   ?? null);
const high   = (poly?.high   ?? twelve?.high   ?? base.high   ?? null);
const low    = (poly?.low    ?? twelve?.low    ?? base.low    ?? null);
const vwap   = (poly?.vwap   ?? base.vwap      ?? null);
const volume = (poly?.volume ?? twelve?.volume ?? base.volume ?? null);
const barTime = poly?.barTime ?? twelve?.barTime ?? null;

// --- pick a benchmark price if cost basis is missing ---
const prevCloseFromTwelve = (twelveObj?.values?.[1]?.close != null)
  ? Number(twelveObj.values[1].close)
  : null;

const benchPrice =
  (base.avgCost != null ? Number(base.avgCost) : null) ??
  (base.entryPrice != null ? Number(base.entryPrice) : null) ??
  prevCloseFromTwelve ?? null;

// compute costBasis (keep your real cost if provided; else leave 0)
const costBasis = Number(
  base.costBasis ??
  (base.avgCost != null ? Number(base.avgCost) * qty : 0) ??
  0
);

const value = qty * Number(price || 0);
const unrealizedPnL = value - costBasis;

// % PnL since entry, or fallback to change vs benchmark
let unrealizedPnLPct = 0;
if (costBasis > 0) {
  unrealizedPnLPct = (unrealizedPnL / costBasis) * 100;
} else if (qty > 0 && benchPrice && benchPrice > 0) {
  unrealizedPnLPct = ((Number(price || 0) / benchPrice) - 1) * 100;
}

// ---- time-series risk metrics if TwelveData values[] present ----
let volatility = 0;
let sharpeRatio = 0;

if (Array.isArray(twelveObj?.values) && twelveObj.values.length >= 20) {
  const closes = twelveObj.values
    .map(v => Number(v.close))
    .filter(n => Number.isFinite(n));

  const rets = [];
  for (let i = 0; i < closes.length - 1; i++) {
    const p0 = closes[i], p1 = closes[i + 1];
    if (p0 > 0 && p1 > 0) rets.push((p0 / p1) - 1);
  }

  if (rets.length >= 10) {
    const mean = rets.reduce((a,b)=>a+b,0) / rets.length;
    const variance = rets.reduce((a,b)=>a + (b - mean) ** 2, 0) / (rets.length - 1);
    const stdPerHour = Math.sqrt(variance);

    const hoursPerYear = 6.5 * 252;
    volatility = stdPerHour * Math.sqrt(hoursPerYear) * 100;

    const meanPerYear = mean * hoursPerYear;
    sharpeRatio = (stdPerHour > 0)
      ? (meanPerYear / (stdPerHour * Math.sqrt(hoursPerYear)))
      : 0;
  }
}

// ---- metrics block using cost basis if present; else fallback to benchmark ----
const totalValue = value;
const totalCost  = costBasis;
const totalUnrealizedPnL = unrealizedPnL;
const totalUnrealizedPnLPct = unrealizedPnLPct;

const portfolioReturn = (totalCost > 0)
  ? ((totalValue - totalCost) / totalCost) * 100
  : (benchPrice && benchPrice > 0 && qty > 0)
    ? ((Number(price || 0) / benchPrice) - 1) * 100
    : 0;

const dataSource =
  poly?.source ?? twelve?.source ??
  (base.apiSource ? String(base.apiSource) : 'unknown');

// ---- final holding ----
const holding = {
  symbol,
  quantity: qty,
  currentPrice: Number(price || 0),
  open, high, low, vwap, volume, barTime,
  value,
  costBasis,
  unrealizedPnL,
  unrealizedPnLPct,
  dataSource,
};

// ---- return one portfolio item ----
const portfolio = [holding];
const allocation = {};
allocation[symbol] = totalValue > 0 ? 100 : 0;

return [{
  json: {
    portfolio,
    totalValue,
    totalCost,
    totalUnrealizedPnL,
    totalUnrealizedPnLPct,
    allocation,
    metrics: {
      portfolioReturn,
      volatility,
      sharpeRatio,
      maxPosition: value,
      top3Concentration: totalValue > 0 ? 100 : 0,
    },
    timestamp: new Date().toISOString(),
    chatId: base.chatId,
  }
}];

// Generate comprehensive analysis report (no named lookups; reads only from Merge input)

function pickLLM(j) {
  if (!j || typeof j !== 'object') return null;
  return (
    j.output ??
    j.choices?.[0]?.message?.content ??
    j.message?.content ??
    j.content ??
    j.text ??
    (typeof j === 'string' ? j : null)
  );
}

function isPortfolioObj(j) {
  if (!j || typeof j !== 'object') return false;
  // Our aggregate node usually has these:
  if (j.portfolio || j.allocation || j.metrics) return true;
  // Sometimes the object is wrapped: { data: { portfolio... } }
  if (j.data && (j.data.portfolio || j.data.allocation || j.data.metrics)) return true;
  return false;
}

try {
  const inputs = $input.all().map(i => i.json).filter(Boolean);

  // 1) Find portfolio data among merged inputs
  let data = inputs.find(isPortfolioObj) || {};
  if (data.data && isPortfolioObj(data.data)) data = data.data; // unwrap { data: {...} } if present

  // 2) Collect advisor texts from the remaining inputs
  const advisorTexts = inputs
    .map(pickLLM)
    .filter(t => typeof t === 'string' && t.trim().length);

  // Try to map them in order (Buffett, Dalio, Wood). If fewer found, fill with placeholder.
  const [buffett, dalio, wood] = [
    advisorTexts[0] || 'Analysis unavailable',
    advisorTexts[1] || 'Analysis unavailable',
    advisorTexts[2] || 'Analysis unavailable',
  ];

  // 3) Helpers
  const pct = (n) => (Number.isFinite(Number(n)) ? Number(n).toFixed(2) : '0.00');
  const num = (n) => (Number.isFinite(Number(n)) ? Number(n).toLocaleString() : '0');

  // 4) Allocation bars
  let allocationSection = 'No allocation data.';
  if (data?.allocation && typeof data.allocation === 'object') {
    const entries = Object.entries(data.allocation);
    if (entries.length) {
      allocationSection = entries
        .map(([sym, p]) => {
          const pNum = Number(p) || 0;
          const bar = '█'.repeat(Math.max(1, Math.round(pNum / 5)));
          return `${String(sym).padEnd(10)} ${bar} ${pct(pNum)}%`;
        })
        .join('\n');
    }
  }

  // 5) Portfolio summary
  const totalValue = Number(data?.totalValue) || 0;
  const totalCost  = Number(data?.totalCost)  || 0;
  const uPnL       = Number(data?.totalUnrealizedPnL) || 0;
  const uPnLPct    = Number(data?.totalUnrealizedPnLPct) || 0;
  const assets     = Array.isArray(data?.portfolio) ? data.portfolio.length : 0;
  const ts         = data?.timestamp ? new Date(data.timestamp).toLocaleString() : 'n/a';

  const m = data?.metrics ?? {};
  const portRet   = Number(m.portfolioReturn) || 0;
  const vol       = Number(m.volatility) || 0;
  const sharpe    = Number(m.sharpeRatio) || 0;
  const maxPos    = Number(m.maxPosition) || 0;
  const top3Con   = Number(m.top3Concentration) || 0;

  // 6) Report
  let report = `📊 **AI HEDGE FUND ANALYSIS**
════════════════════════════════════════

💰 **Portfolio Summary**
Total Value: ${num(totalValue)}
Total Cost: ${num(totalCost)}
Unrealized P&L: ${num(uPnL)} (${pct(uPnLPct)}%)
Assets: ${assets}
Timestamp: ${ts}

📈 **Asset Allocation**
${allocationSection}

📊 **Risk Metrics**
• Portfolio Return: ${pct(portRet)}%
• Volatility: ${pct(vol)}%
• Sharpe Ratio: ${pct(sharpe)}
• Max Position: ${num(maxPos)}
• Top 3 Concentration: ${pct(top3Con)}%

════════════════════════════════════════

🎩 **Warren Buffett** - Value Investing

${buffett}

════════════════════════════════════════

🌊 **Ray Dalio** - Macro & Risk Parity

${dalio}

════════════════════════════════════════

🚀 **Cathie Wood** - Disruptive Innovation

${wood}

════════════════════════════════════════

⚠️ **Disclaimer:** This analysis is generated by AI and does not constitute financial advice. Always consult a licensed financial advisor before making investment decisions.`;

  return [{
    json: {
      report,
      chatId: data?.chatId ?? null,
      data,
      advisors: { buffett, dalio, wood }
    }
  }];
} catch (error) {
  return [{
    json: {
      error: true,
      message: `Error generating report: ${error.message}`,
      chatId: null
    }
  }];
}

// Calculate advanced risk metrics
try {
  const dbResult = $input.all();

  if (!dbResult || dbResult.length === 0 || !dbResult[0].json.holdings) {
    return [{
      error: true,
      chatId: $('Parse Command').first().json.chatId,
      message: '❌ No portfolio found for risk analysis.'
    }];
  }

  const portfolio = dbResult[0].json;
  const holdings = JSON.parse(portfolio.holdings);

  // Get historical snapshots for volatility calculation
  const snapshots = $input.all().slice(0, 30); // Last 30 days

  let volatility = 0;
  let maxDrawdown = 0;
  let valueAtRisk95 = 0;
  let beta = 1.0; // Simplified

  if (snapshots.length > 1) {
    const returns = [];
    for (let i = 1; i < snapshots.length; i++) {
      const prevValue = parseFloat(snapshots[i].json.total_value || 0);
      const currValue = parseFloat(snapshots[i-1].json.total_value || 0);
      if (prevValue > 0) {
        returns.push((currValue - prevValue) / prevValue * 100);
      }
    }

    if (returns.length > 0) {
      // Calculate volatility (standard deviation)
      const avgReturn = returns.reduce((a, b) => a + b, 0) / returns.length;
      const squaredDiffs = returns.map(r => Math.pow(r - avgReturn, 2));
      volatility = Math.sqrt(squaredDiffs.reduce((a, b) => a + b, 0) / returns.length);

      // Annualized volatility
      volatility = volatility * Math.sqrt(252); // Trading days

      // Calculate max drawdown
      let peak = snapshots[0].json.total_value;
      for (const snap of snapshots) {
        const value = parseFloat(snap.json.total_value || 0);
        if (value > peak) peak = value;
        const drawdown = ((value - peak) / peak) * 100;
        if (drawdown < maxDrawdown) maxDrawdown = drawdown;
      }

      // Value at Risk (95% confidence) - simplified
      returns.sort((a, b) => a - b);
      const varIndex = Math.floor(returns.length * 0.05);
      valueAtRisk95 = returns[varIndex] || 0;
    }
  }

  // Calculate concentration risk
  const totalValue = holdings.reduce((sum, h) => sum + (h.quantity * (h.currentPrice || 0)), 0);
  const concentrations = holdings.map(h => {
    const value = h.quantity * (h.currentPrice || 0);
    return {
      symbol: h.symbol,
      concentration: totalValue > 0 ? (value / totalValue * 100) : 0
    };
  }).sort((a, b) => b.concentration - a.concentration);

  const top1 = concentrations[0]?.concentration || 0;
  const top5 = concentrations.slice(0, 5).reduce((sum, c) => sum + c.concentration, 0);

  // Risk assessment
  let riskLevel = 'Low';
  let riskScore = 0;

  if (volatility > 30) riskScore += 3;
  else if (volatility > 20) riskScore += 2;
  else if (volatility > 15) riskScore += 1;

  if (top1 > 40) riskScore += 2;
  else if (top1 > 25) riskScore += 1;

  if (maxDrawdown < -20) riskScore += 2;
  else if (maxDrawdown < -10) riskScore += 1;

  if (riskScore >= 5) riskLevel = 'High';
  else if (riskScore >= 3) riskLevel = 'Medium';

  return [{
    holdings,
    riskMetrics: {
      volatility: volatility.toFixed(2),
      maxDrawdown: maxDrawdown.toFixed(2),
      valueAtRisk95: valueAtRisk95.toFixed(2),
      beta: beta.toFixed(2),
      top1Concentration: top1.toFixed(1),
      top5Concentration: top5.toFixed(1),
      riskLevel,
      riskScore
    },
    concentrations: concentrations.slice(0, 5),
    chatId: $('Parse Command').first().json.chatId,
    userId: portfolio.user_id
  }];

} catch (error) {
  return [{
    error: true,
    message: `Error calculating risk: ${error.message}`,
    chatId: $('Parse Command').first().json.chatId
  }];
}

// Generate rebalancing recommendations
try {
  const dbResult = $input.all();

  if (!dbResult || dbResult.length === 0 || !dbResult[0].json.holdings) {
    return [{
      error: true,
      chatId: $('Parse Command').first().json.chatId,
      message: '❌ No portfolio found for rebalancing.'
    }];
  }

  const portfolio = dbResult[0].json;
  const holdings = JSON.parse(portfolio.holdings);

  // Target allocations (customizable)
  const targets = {
    'Stock': 40,
    'Crypto': 20,
    'Bond': 25,
    'Commodity': 15
  };

  // Calculate current allocations
  const totalValue = holdings.reduce((sum, h) => sum + (h.quantity * (h.currentPrice || 100)), 0);

  const current = {};
  holdings.forEach(h => {
    const value = h.quantity * (h.currentPrice || 100);
    current[h.assetType] = (current[h.assetType] || 0) + value;
  });

  const currentPct = {};
  Object.keys(current).forEach(type => {
    currentPct[type] = (current[type] / totalValue * 100);
  });

  // Calculate drift and recommendations
  const drifts = [];
  Object.keys(targets).forEach(type => {
    const target = targets[type];
    const actual = currentPct[type] || 0;
    const drift = actual - target;
    const targetValue = totalValue * (target / 100);
    const actualValue = current[type] || 0;
    const dollarChange = targetValue - actualValue;

    if (Math.abs(drift) > 5) { // 5% threshold
      drifts.push({
        assetType: type,
        current: actual.toFixed(1),
        target,
        drift: drift.toFixed(1),
        dollarChange: dollarChange.toFixed(2),
        action: drift > 0 ? 'SELL' : 'BUY'
      });
    }
  });

  // Sort by absolute drift
  drifts.sort((a, b) => Math.abs(parseFloat(b.drift)) - Math.abs(parseFloat(a.drift)));

  // Specific asset recommendations
  const assetRecommendations = [];
  holdings.forEach(h => {
    const value = h.quantity * (h.currentPrice || 100);
    const concentration = (value / totalValue * 100);

    if (concentration > 25) {
      assetRecommendations.push({
        symbol: h.symbol,
        action: 'REDUCE',
        reason: `Over-concentrated at ${concentration.toFixed(1)}%`,
        suggestion: `Consider selling ${Math.floor(h.quantity * 0.25)} units`
      });
    }
  });

  return [{
    holdings,
    totalValue: totalValue.toFixed(2),
    targets,
    currentPct,
    drifts,
    assetRecommendations,
    needsRebalancing: drifts.length > 0,
    chatId: $('Parse Command').first().json.chatId,
    userId: portfolio.user_id
  }];

} catch (error) {
  return [{
    error: true,
    message: `Error generating rebalancing: ${error.message}`,
    chatId: $('Parse Command').first().json.chatId
  }];
}

