// Calculate historical performance metrics
try {
  const snapshots = $input.all();

  if (!snapshots || snapshots.length === 0) {
    return [{
      error: true,
      chatId: $('Parse Command').first().json.chatId,
      message: '❌ No historical data available yet.\n\nPerformance tracking requires at least 2 days of data. Keep using the bot and check back tomorrow!'
    }];
  }

  // Sort by date (newest first)
  const data = snapshots.map(s => ({
    date: s.json.date,
    value: parseFloat(s.json.total_value),
    metrics: typeof s.json.metrics === 'string' ? JSON.parse(s.json.metrics) : s.json.metrics
  })).reverse();

  if (data.length < 2) {
    return [{
      error: true,
      chatId: $('Parse Command').first().json.chatId,
      message: '❌ Insufficient data for performance analysis.\n\nNeed at least 2 data points. Current snapshots: ' + data.length
    }];
  }

  // Calculate returns
  const returns = [];
  for (let i = 1; i < data.length; i++) {
    const prevValue = data[i-1].value;
    const currValue = data[i].value;
    if (prevValue > 0) {
      const dailyReturn = ((currValue - prevValue) / prevValue) * 100;
      returns.push(dailyReturn);
    }
  }

  // Performance metrics
  const latestValue = data[data.length - 1].value;
  const oldestValue = data[0].value;
  const totalReturn = oldestValue > 0 ? ((latestValue - oldestValue) / oldestValue * 100) : 0;

  const avgDailyReturn = returns.reduce((a, b) => a + b, 0) / returns.length;
  const annualizedReturn = avgDailyReturn * 252; // Trading days

  // Volatility
  const variance = returns.reduce((sum, r) => sum + Math.pow(r - avgDailyReturn, 2), 0) / returns.length;
  const dailyVolatility = Math.sqrt(variance);
  const annualizedVolatility = dailyVolatility * Math.sqrt(252);

  // Best and worst days
  const bestDay = Math.max(...returns);
  const worstDay = Math.min(...returns);

  // Winning days
  const winningDays = returns.filter(r => r > 0).length;
  const winRate = (winningDays / returns.length * 100);

  // Drawdown calculation
  let peak = data[0].value;
  let maxDrawdown = 0;
  let currentDrawdown = 0;

  for (const point of data) {
    if (point.value > peak) {
      peak = point.value;
      currentDrawdown = 0;
    } else {
      currentDrawdown = ((point.value - peak) / peak) * 100;
      if (currentDrawdown < maxDrawdown) {
        maxDrawdown = currentDrawdown;
      }
    }
  }

  // Sharpe ratio
  const riskFreeRate = 4.5 / 252; // Daily risk-free rate
  const excessReturn = avgDailyReturn - riskFreeRate;
  const sharpeRatio = dailyVolatility > 0 ? (excessReturn / dailyVolatility) * Math.sqrt(252) : 0;

  // Format historical data for chart
  const chartData = data.slice(-7).map(d => ({
    date: d.date,
    value: d.value.toFixed(2)
  }));

  return [{
    performance: {
      totalReturn: totalReturn.toFixed(2),
      annualizedReturn: annualizedReturn.toFixed(2),
      annualizedVolatility: annualizedVolatility.toFixed(2),
      sharpeRatio: sharpeRatio.toFixed(2),
      maxDrawdown: maxDrawdown.toFixed(2),
      bestDay: bestDay.toFixed(2),
      worstDay: worstDay.toFixed(2),
      winRate: winRate.toFixed(1),
      daysTracked: data.length
    },
    currentValue: latestValue.toFixed(2),
    initialValue: oldestValue.toFixed(2),
    chartData,
    chatId: $('Parse Command').first().json.chatId
  }];

} catch (error) {
  return [{
    error: true,
    message: `Error calculating performance: ${error.message}`,
    chatId: $('Parse Command').first().json.chatId
  }];
}

