// Chunk the generated report into Telegram-safe messages.
// Input shape expected from previous node: { report, chatId, ... }

const MAX = 3500; // keep well under Telegram's ~4096 limit (emojis/formatting safety)

// Greedy chunker that prefers paragraph boundaries, then hard-splits when needed
function chunkByParagraph(text, max) {
  const paras = String(text).split(/\n{2,}/); // split on blank lines
  const out = [];
  let buf = '';

  function pushBuf() {
    if (buf.length) { out.push(buf); buf = ''; }
  }

  for (const p of paras) {
    const block = (buf ? '\n\n' : '') + p;
    if ((buf + block).length <= max) {
      buf += block;
    } else {
      pushBuf();
      if (p.length <= max) {
        buf = p; // start new buffer with this paragraph
      } else {
        // paragraph itself is too big -> hard-split
        let s = p;
        while (s.length > max) {
          out.push(s.slice(0, max));
          s = s.slice(max);
        }
        buf = s;
      }
    }
  }
  pushBuf();
  return out;
}

// 1) read input
const inItem = $input.first()?.json || {};
const report = inItem.report;
const chatId = inItem.chatId ?? null;

if (!report) {
  return [{ json: { error: true, message: 'No report to chunk', chatId } }];
}

// (Optional) If your Telegram node uses "Parse Mode: None", leave text as-is.
// If you use "MarkdownV2" or "HTML", you may need escaping/transforming.
// For now we keep the original text. You can uncomment to strip **bold** -> bold:
//
// const safeReport = report.replaceAll(/\*\*(.*?)\*\*/g, '$1');

const parts = chunkByParagraph(report, MAX);
const total = parts.length;

// 2) return one item per chunk -> Telegram node will send one message per item
return parts.map((text, i) => ({
  json: {
    chatId,
    text: `${text}\n\n[${i + 1}/${total}]`
  }
}));
